// PASTE YOUR GOOGLE ALERTS RSS FEED URLS HERE (google.com/alerts → RSS icon).
// One feed per role. Delete lines you don't have feeds for.
const feeds = [
  'PASTE_YOUR_GOOGLE_ALERTS_RSS_FEED_URL',
  'PASTE_YOUR_GOOGLE_ALERTS_RSS_FEED_URL',
  'PASTE_YOUR_GOOGLE_ALERTS_RSS_FEED_URL',
  'PASTE_YOUR_GOOGLE_ALERTS_RSS_FEED_URL',
];
return feeds.filter(u => u.startsWith('http')).map(u => ({ json: { feed_url: u } }));

// Google Alerts wraps links in a redirect — unwrap, keep only LinkedIn job
// pages, normalize (strip tracking params), infer a role hint from the title.
const out = [];
const seen = new Set();
for (const item of $input.all()) {
  let link = item.json.link || '';
  // unwrap https://www.google.com/url?...&url=<real>&...
  const m = link.match(/[?&]url=([^&]+)/);
  if (m) link = decodeURIComponent(m[1]);
  if (!/linkedin\.com\/jobs/i.test(link)) continue;
  // normalize: strip query string / fragments (tracking junk breaks dedupe)
  link = link.split('?')[0].split('#')[0].replace(/\/$/, '');
  if (seen.has(link)) continue;
  seen.add(link);
  const title = String(item.json.title || '').replace(/<[^>]+>/g, ' ').trim();
  const snippet = String(item.json.contentSnippet || item.json.content || '').replace(/<[^>]+>/g, ' ').trim();
  const t = (title + ' ' + snippet).toLowerCase();
  let role_hint = 'other';
  if (/product|\bapm\b/.test(t)) role_hint = 'pm';
  else if (/market|growth|brand|community|content/.test(t)) role_hint = 'growth';
  else if (/analyst|analytics|\bbi\b/.test(t)) role_hint = 'analyst';
  else if (/software|developer|\bsde\b|engineer|full.?stack|backend|frontend/.test(t)) role_hint = 'swe';
  out.push({ json: { source: 'linkedin', source_url: link, role_hint, rss_title: title, rss_snippet: snippet } });
}
return out;

const known = new Set(
  $('Fetch known URLs').all().map(i => i.json.source_url).filter(Boolean)
);
return $('Unwrap + filter links').all().filter(i => !known.has(i.json.source_url));

// LinkedIn sometimes serves guest pages, sometimes an auth wall.
// Use the page text when we got it; otherwise fall back to the RSS
// title + snippet (Claude still gets title/company/role from those).
const SYSTEM = 'You extract structured data from internship job postings in India. Output ONLY a valid JSON object, no markdown fences, no commentary. If a field is not stated use null (arrays: [], booleans: false). Never guess stipend numbers. Schema: {"title":string,"company":string,"role_category":"pm"|"growth"|"analyst"|"swe"|"other","location":string|null,"city":string|null,"is_remote":boolean,"stipend_min_inr":integer|null,"stipend_max_inr":integer|null,"duration_months":number|null,"yoe_required":number,"ppo_offered":boolean,"posted_at":"YYYY-MM-DD"|null,"skills":[string],"perks":[string]}. Rules: stipend is monthly INR ("8-12k" -> min 8000 max 12000; "unpaid" -> 0; convert lakhs/year to monthly). city: one normalized Indian city (Bangalore, Mumbai, Delhi NCR, Hyderabad, Pune, Chennai, Kolkata, or the proper city name), null if remote-only. yoe_required: years of prior experience asked, 0 if none mentioned. posted_at: resolve relative dates against the given today date. skills: lowercase canonical tags (excel, sql, power bi, google analytics, figma, a/b testing, seo, python, react, communication...), exclude generic filler like "hardworking". role_category: pm=product roles, growth=marketing/growth/community, analyst=data/business/product analyst, swe=software/web/app/backend/frontend/qa/devops/ml engineering, else other. If the text is only a headline/snippet, extract what you can and leave the rest null.';
const srcs = $('Filter new postings').all();
const today = new Date().toISOString().slice(0, 10);
const out = [];
$input.all().forEach((item, i) => {
  const meta = srcs[i] ? srcs[i].json : {};
  if (!meta.source_url) return;
  const html = item.json.data || '';
  let text = html
    .replace(/<script[\s\S]*?<\/script>/gi, ' ')
    .replace(/<style[\s\S]*?<\/style>/gi, ' ')
    .replace(/<[^>]+>/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
  // auth wall / empty page -> fall back to RSS metadata
  const authWalled = text.length < 500 || /join linkedin|sign in to view|authwall/i.test(text.slice(0, 2000));
  if (authWalled) {
    text = `Headline: ${meta.rss_title}\nSnippet: ${meta.rss_snippet}`;
  } else {
    text = text.slice(0, 6000);
  }
  out.push({ json: {
    ...meta,
    raw_text: text,
    anthropic_body: {
      model: 'claude-haiku-4-5',
      max_tokens: 1024,
      temperature: 0,
      system: SYSTEM,
      messages: [{ role: 'user', content: `Today's date: ${today}\n\nPosting URL: ${meta.source_url}\nPosting text:\n---\n${text}\n---` }]
    }
  }});
});
return out;

const reqs = $('Build Claude request').all();
const out = [];
$input.all().forEach((item, i) => {
  try {
    const txt = (item.json.content && item.json.content[0] && item.json.content[0].text) || '';
    const j = JSON.parse(txt.replace(/^```json\s*/i, '').replace(/```\s*$/, '').trim());
    const meta = reqs[i] ? reqs[i].json : {};
    out.push({ json: {
      source: 'linkedin',
      source_url: meta.source_url,
      raw_text: meta.raw_text,
      title: j.title || meta.rss_title,
      company: j.company,
      role_category: ['pm','growth','analyst','swe','other'].includes(j.role_category) ? j.role_category : (meta.role_hint || 'other'),
      location: j.location,
      city: j.city,
      is_remote: !!j.is_remote,
      stipend_min_inr: Number.isFinite(j.stipend_min_inr) ? Math.round(j.stipend_min_inr) : null,
      stipend_max_inr: Number.isFinite(j.stipend_max_inr) ? Math.round(j.stipend_max_inr) : null,
      duration_months: j.duration_months,
      yoe_required: Number.isFinite(j.yoe_required) ? j.yoe_required : 0,
      ppo_offered: typeof j.ppo_offered === 'boolean' ? j.ppo_offered : null,
      posted_at: /^\d{4}-\d{2}-\d{2}$/.test(j.posted_at || '') ? j.posted_at : null,
      skills: Array.isArray(j.skills) ? j.skills.map(s => String(s).toLowerCase().trim()) : [],
      perks: Array.isArray(j.perks) ? j.perks : [],
      extraction_model: 'claude-haiku-4-5',
      extraction_json: j
    }});
  } catch (e) { /* skip unparseable */ }
});
return out;
